static bool IsSensitiveResponseHeader(string headerName)
{
    var sensitive = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
    {
        "Set-Cookie",
        "Authorization",
        "Proxy-Authorization",
        "WWW-Authenticate",
        "Proxy-Authenticate"
    };
