}

static async Task<bool> IsExternalHostSafe(string host, ILogger logger)
{
    try
    {
        var addresses = await System.Net.Dns.GetHostAddressesAsync(host);

        foreach (var address in addresses)
        {
            if (System.Net.IPAddress.IsLoopback(address))
                return false;

            byte[] bytes = address.GetAddressBytes();

            if (address.AddressFamily == System.Net.Sockets.AddressFamily.InterNetwork)
            {
                // 10.0.0.0/8
                if (bytes[0] == 10)
                    return false;

                // 172.16.0.0/12
                if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
                    return false;

                // 192.168.0.0/16
                if (bytes[0] == 192 && bytes[1] == 168)
                    return false;

                // 169.254.0.0/16 (link-local / cloud metadata)
                if (bytes[0] == 169 && bytes[1] == 254)
                    return false;

                // 127.0.0.0/8
                if (bytes[0] == 127)
                    return false;

                // 0.0.0.0/8
                if (bytes[0] == 0)
                    return false;
            }

            if (address.AddressFamily == System.Net.Sockets.AddressFamily.InterNetworkV6)
            {
                if (address.IsIPv6LinkLocal || address.IsIPv6SiteLocal)
                    return false;

                // Block IPv6 loopback ::1
                if (System.Net.IPAddress.IPv6Loopback.Equals(address))
                    return false;

                // Block IPv4-mapped IPv6 addresses that map to private ranges
                if (address.IsIPv4MappedToIPv6)
                {
                    var mappedV4 = address.MapToIPv4();
                    byte[] v4Bytes = mappedV4.GetAddressBytes();
                    if (v4Bytes[0] == 10 ||
                        (v4Bytes[0] == 172 && v4Bytes[1] >= 16 && v4Bytes[1] <= 31) ||
                        (v4Bytes[0] == 192 && v4Bytes[1] == 168) ||
                        (v4Bytes[0] == 169 && v4Bytes[1] == 254) ||
                        v4Bytes[0] == 127 ||
                        v4Bytes[0] == 0)
                        return false;
                }
            }
        }

        return true;
    }
    catch (Exception ex)
    {
        logger.LogWarning(ex, "DNS resolution failed for host: {Host}", host);
        return false;
    }
}

public class AllowedHostsService
{
