        _allowedHosts = hosts != null
            ? new HashSet<string>(hosts, StringComparer.OrdinalIgnoreCase)
            : new HashSet<string>(StringComparer.OrdinalIgnoreCase)
            {
                // Default allowed hosts - configure via appsettings.json
                "api.github.com",
                "hooks.slack.com",
                "api.stripe.com",
                "api.twilio.com",
                "oapi.dingtalk.com"
            };
    }

    public bool IsHostAllowed(string host)
    {
        return _allowedHosts.Contains(host);
